#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10,Mod=1e9+7;
int ta[N<<2],tg[N<<2],off[N<<2],on[N<<2],n,s,ons[N<<2],offs[N],onc[N<<2];
inline void DN(int &x){x>=Mod?x-=Mod:0;}
inline void update(int x)
{
	if(on[x]>0)return;
	ons[x]=0;offs[x]=0;
	DN(ons[x]+=ons[x<<1]);
	DN(offs[x]+=offs[x<<1]);
	DN(ons[x]+=ons[x<<1|1]);
	DN(offs[x]+=offs[x<<1|1]);
	onc[x]=onc[x<<1]+onc[x<<1|1];

}
inline void Add(int x,int add,int mul)
{
	ta[x]=(1ll*mul*ta[x]+add)%Mod;
	tg[x]=1ll*mul*tg[x]%Mod;
	ons[x]=(1ll*mul*ons[x]+1ll*add*onc[x])%Mod;
}
inline void pushdown(int x)
{
	if(!on[x<<1])Add(x<<1,ta[x],tg[x]);
	if(!on[x<<1|1])Add(x<<1|1,ta[x],tg[x]);
	tg[x]=1;ta[x]=0;
}
inline void add(int ql,int qr,int v,int l=1,int r=n,int x=1)
{
	if(on[x]>0)return;
	if(ql<=l&&r<=qr)
	{
		ons[x]=(1ll*v*onc[x]+ons[x])%Mod;
		DN(ta[x]+=v);return;
	}
	pushdown(x);int mid=(l+r)>>1;
	if(ql<=mid)add(ql,qr,v,l,mid,x<<1);
	if(qr>mid)add(ql,qr,v,mid+1,r,x<<1|1);
	update(x);
}
inline void mul(int ql,int qr,int v,int l=1,int r=n,int x=1)
{
	if(on[x]>0)return;
	if(ql<=l&&r<=qr)
	{
		ons[x]=1ll*v*ons[x]%Mod;
		tg[x]=1ll*tg[x]*v%Mod;
		ta[x]=1ll*ta[x]*v%Mod;return;
	}
	int mid=(l+r)>>1;pushdown(x);
	if(ql<=mid)mul(ql,qr,v,l,mid,x<<1);
	if(qr>mid)mul(ql,qr,v,mid+1,r,x<<1|1);
	update(x);
}
inline void lock(int ql,int qr,int l=1,int r=n,int x=1)
{
	if(ql<=l&&r<=qr)
	{
		if(l!=r)pushdown(x);
		if(!(on[x]++))
		{
			DN(offs[x]+=ons[x]);
			ons[x]=0;onc[x]=0;
		}
		return;
	}
	int mid=(l+r)>>1;pushdown(x);
	if(ql<=mid)lock(ql,qr,l,mid,x<<1);
	if(qr>mid)lock(ql,qr,mid+1,r,x<<1|1);
	update(x);
}
inline void unlock(int ql,int qr,int l=1,int r=n,int x=1)
{
	if(ql<=l&&r<=qr)
	{
		if(!(--on[x]))
		{
			if(l==r){swap(ons[x],offs[x]);onc[x]=1;}
			else update(x);
		}
		return;
	}
	int mid=(l+r)>>1;pushdown(x);
	if(ql<=mid)unlock(ql,qr,l,mid,x<<1);
	if(qr>mid)unlock(ql,qr,mid+1,r,x<<1|1);
	update(x);
}
inline int qry(int ql,int qr,int l=1,int r=n,int x=1)
{
	if(ql<=l&&r<=qr){return (offs[x]+ons[x])%Mod;}
	int res=0,mid=(l+r)>>1;pushdown(x);
	if(ql<=mid)DN(res+=qry(ql,qr,l,mid,x<<1));
	if(qr>mid)DN(res+=qry(ql,qr,mid+1,r,x<<1|1));
	return res;
}
struct Node{int l,r;};vector<Node> v[N];int a[N];
inline void Init(int l=1,int r=n,int x=1)
{
	tg[x]=1;if(l==r){ons[x]=a[l];onc[x]=1;return;}int mid=(l+r)>>1;
	Init(l,mid,x<<1);Init(mid+1,r,x<<1|1);update(x);
}
int main()
{
	n=read();int Q=read();
	rep(1,n,i)a[i]=read();Init();
//	printf("a :: ");rep(1,n,i)printf("%d ",qry(i,i));puts("");
	rep(1,Q,i)
	{
		int op=read(),l=read(),r=read();
		if(op==1)add(l,r,read());
		if(op==2)mul(l,r,read());
		if(op==3)
		{
			int x=read();lock(l,r);
			if(i+x<=Q)v[i+x].push_back({l,r});
		}
		if(op==4){printf("%d\n",qry(l,r));}
		for(Node x:v[i])unlock(x.l,x.r);
//		printf("a :: ");rep(1,n,i)printf("%d ",qry(i,i));puts("");
	}

}
